import React from 'react';
import clsx from 'clsx';
import { useColorPickerContext } from '../ColorPickerContext';

export const ColorPickerContainer = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<'div'>>(
  ({ className, ...restProps }, ref) => {
    const { rootCssScope } = useColorPickerContext();
    return <div className={clsx(rootCssScope(), className)} ref={ref} {...restProps} />;
  },
);
